112→internal class ReducedIntFormatterStructure<in T>(
113→    private val number: (T) -> Int,
114→    private val digits: Int,
115→    private val base: Int,
116→): FormatterStructure<T> {
117→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
118→        val number = number(obj)
119→        if (number - base in 0 until POWERS_OF_TEN[digits]) {
120→            // the number fits
121→            val numberStr = (number % POWERS_OF_TEN[digits]).toString()
122→            val zeroPaddingStr = '0'.toString().repeat(maxOf(0, digits - numberStr.length))
123→            builder.append(zeroPaddingStr, numberStr)
124→        } else {
125→            if (number >= 0)
126→                builder.append("+")
127→            builder.append(number.toString())
128→        }
129→    }
130→}
